"use client";

import { useEffect, useRef } from "react";
import type { Square } from "chess.js";
import { useGameStore, type PlayerColor } from "@/store/gameStore";
import { getStockfish } from "@/lib/stockfishClient";
import { classifyMove } from "@/lib/moveClassifier";
import { uciToSan } from "@/lib/chessUtils";
import { fetchMoveAdvice } from "@/lib/ollama";

type PrevAnalysis = {
  fen: string;
  evalCp: number | null;
  mate: number | null;
  bestMoveUci: string | null;
};

export function useGameEngine() {
  const phase = useGameStore((s) => s.phase);
  const fen = useGameStore((s) => s.fen);
  const elo = useGameStore((s) => s.elo);

  const processedFenRef = useRef<string | null>(null);
  const isEngineThinkingRef = useRef<boolean>(false);

  const prevAnalysisRef = useRef<PrevAnalysis>({
    fen: fen,
    evalCp: 20,
    mate: null,
    bestMoveUci: null,
  });

  // 1. Warm up Stockfish engine
  useEffect(() => {
    if (phase === "playing") {
      getStockfish().waitUntilReady();
    }
  }, [phase]);

  // 2. Reset tracking when new game starts
  useEffect(() => {
    if (phase === "playing") {
      processedFenRef.current = null;
      isEngineThinkingRef.current = false;
      prevAnalysisRef.current = {
        fen,
        evalCp: 20,
        mate: null,
        bestMoveUci: null,
      };
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [phase]);

  // 3. Game Engine Controller Loop
  useEffect(() => {
    if (phase !== "playing") return;
    if (processedFenRef.current === fen || isEngineThinkingRef.current) return;

    let isSubscribed = true;
    isEngineThinkingRef.current = true;

    (async () => {
      try {
        const store = useGameStore.getState();
        const engine = getStockfish();
        const game = store.game;
        const verboseHistory = game.history({ verbose: true });
        const lastMove = verboseHistory[verboseHistory.length - 1];

        // --- PHASE A: Analyze current position ---
        store.setAnalysis({ thinking: true });
        const info = await engine.analyze(fen, 12, (partial) => {
          if (isSubscribed) store.setAnalysis(partial);
        });

        if (!isSubscribed) return;

        const bestMoveSanNow = uciToSan(info.bestMoveUci, fen);
        store.setAnalysis({
          ...info,
          bestMoveSan: bestMoveSanNow,
          thinking: false,
        });

        // --- PHASE B: Evaluate Last Move & Request Ollama Advice ---
        if (lastMove) {
          const moverColor: PlayerColor = lastMove.color as PlayerColor;
          const prev = prevAnalysisRef.current;
          const moveUci = `${lastMove.from}${lastMove.to}${lastMove.promotion ?? ""}`;
          const wasBest =
            !!prev.bestMoveUci &&
            prev.bestMoveUci.startsWith(moveUci.slice(0, 4));

          const classification = classifyMove(
            moverColor,
            prev.evalCp,
            prev.mate,
            info.evalCp,
            info.mate,
            wasBest,
          );

          store.pushEvalPoint({
            moveNumber: Math.ceil(verboseHistory.length / 2),
            san: lastMove.san,
            fen,
            fenBefore: prev.fen,
            byColor: moverColor,
            evalBefore: prev.evalCp,
            evalAfter: info.evalCp,
            mateBefore: prev.mate,
            mateAfter: info.mate,
            bestMoveBefore: prev.bestMoveUci,
            classification,
          });

          // Fetch Advice for Player Move
          if (moverColor === store.playerColor) {
            const bestMoveSanBefore = uciToSan(prev.bestMoveUci, prev.fen);
            store.setAdvice({ loading: true });
            try {
              const text = await fetchMoveAdvice({
                fen,
                lastMoveSan: lastMove.san,
                moverColor,
                evalCp: info.evalCp,
                mate: info.mate,
                bestMoveSan: bestMoveSanBefore,
                classification,
              });
              if (isSubscribed) store.setAdvice({ text, loading: false });
            } catch (err) {
              if (isSubscribed) {
                store.setAdvice({
                  text:
                    err instanceof Error
                      ? err.message
                      : "เรียก Ollama ไม่สำเร็จ ตรวจสอบว่า Ollama กำลังรันอยู่",
                  loading: false,
                });
              }
            }
          }
        }

        prevAnalysisRef.current = {
          fen,
          evalCp: info.evalCp,
          mate: info.mate,
          bestMoveUci: info.bestMoveUci,
        };

        // Mark current FEN as completely processed before AI move
        processedFenRef.current = fen;

        // --- PHASE C: Execute Opponent AI Move ---
        const isGameOver = game.isGameOver();
        const isAITurn = game.turn() !== store.playerColor;

        if (!isGameOver && isAITurn && isSubscribed) {
          const uci = await engine.getEngineMove(fen, elo, 500);
          if (uci && isSubscribed) {
            useGameStore.getState().applyEngineMove(uci);
          }
        }
      } catch (error) {
        console.error("Game engine processing error:", error);
      } finally {
        isEngineThinkingRef.current = false;
      }
    })();

    return () => {
      isSubscribed = false;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fen, phase, elo]);

  function onDrop({
    sourceSquare,
    targetSquare,
  }: {
    sourceSquare: string;
    targetSquare: string | null;
  }): boolean {
    if (!targetSquare) return false;
    const store = useGameStore.getState();
    if (store.game.turn() !== store.playerColor) return false;

    const moveSuccess = store.makeMove(
      sourceSquare as Square,
      targetSquare as Square,
      "q",
    );

    if (moveSuccess) {
      // ล้างค่า Hint เมื่อเดินสำเร็จ
      if (store.clearHint) {
        store.clearHint();
      } else {
        store.setHint?.(null);
      }
    }

    return moveSuccess;
  }

  function undo() {
    getStockfish().stop();
    isEngineThinkingRef.current = false;
    processedFenRef.current = null;
    useGameStore.getState().undoLastFullMove();
  }

  function resign() {
    getStockfish().stop();
    isEngineThinkingRef.current = false;
    useGameStore.getState().resign();
  }

  return { onDrop, undo, resign };
}
