"use client";

import { useGameStore } from "@/store/gameStore";
import { useGameEngine } from "@/hooks/useGameEngine";

export default function GameControls() {
  const phase = useGameStore((s) => s.phase);
  const historyCount = useGameStore((s) => s.history.length);
  const hint = useGameStore((s) => s.hint);
  const hintsRemaining = useGameStore((s) => s.hintsRemaining);
  const bestMoveUci = useGameStore((s) => s.analysis.bestMoveUci);
  const useHintAction = useGameStore((s) => s.useHint);
  const { undo, resign } = useGameEngine();

  const canUndo = phase === "playing" && historyCount > 0;
  const canHint =
    phase === "playing" &&
    hintsRemaining > 0 &&
    !!bestMoveUci &&
    hint?.level !== 2;
  const canResign = phase === "playing";

  function handleResign() {
    if (
      window.confirm(
        "ยืนยันว่าต้องการยอมแพ้เกมนี้ใช่ไหม? การกระทำนี้ย้อนกลับไม่ได้",
      )
    ) {
      resign();
    }
  }

  return (
    <div className="flex items-center gap-2">
      <button
        onClick={undo}
        disabled={!canUndo}
        className="tactical-btn notation text-[11px] px-3 py-2 disabled:opacity-30 disabled:cursor-not-allowed"
      >
        [ ↺ ย้อนตา ]
      </button>
      <button
        onClick={useHintAction}
        disabled={!canHint}
        className="tactical-btn notation text-[11px] px-3 py-2 disabled:opacity-30 disabled:cursor-not-allowed"
      >
        [ 💡 คำใบ้ ({hintsRemaining}) ]
      </button>
      <button
        onClick={handleResign}
        disabled={!canResign}
        className="tactical-btn notation text-[11px] px-3 py-2 text-[var(--accent-crimson)] disabled:opacity-30 disabled:cursor-not-allowed"
      >
        [ ยอมแพ้ ]
      </button>
    </div>
  );
}
